  1→import type { ReactNode } from "react";
  2→import type { Step } from "../../types";
  3→import { formatElapsed, formatStepTime, formatFullDateTime } from "../../utils";
  4→
  5→interface TimelineEntry {
  6→  step: Step;
  7→  content: ReactNode;
  8→}
  9→
 10→interface StepTimelineProps {
 11→  entries: TimelineEntry[];
 12→  sessionStartMs: number | null;
 13→  sessionStartTimestamp?: string | null;
 14→}
 15→
 16→export function StepTimeline({
 17→  entries,
 18→  sessionStartMs,
 19→  sessionStartTimestamp,
 20→}: StepTimelineProps) {
 21→  const hasTimestamps = entries.some((e) => e.step.timestamp);
 22→  if (!hasTimestamps) {
 23→    return (
 24→      <>
 25→        {entries.map((entry) => (
 26→          <div key={entry.step.step_id}>{entry.content}</div>
 27→        ))}
 28→      </>
 29→    );
 30→  }
 31→
 32→  const startMs =
 33→    sessionStartMs ?? findFirstTimestampMs(entries.map((e) => e.step));
 34→
 35→  return (
 36→    <>
 37→      {entries.map((entry, index) => {
 38→        const stepMs = entry.step.timestamp
 39→          ? new Date(entry.step.timestamp).getTime()
 40→          : null;
 41→        const elapsedSeconds =
 42→          startMs != null && stepMs != null
 43→            ? Math.max(0, Math.floor((stepMs - startMs) / 1000))
 44→            : null;
 45→
 46→        const prevEntry = entries[index - 1];
 47→        const prevMs = prevEntry?.step.timestamp
 48→          ? new Date(prevEntry.step.timestamp).getTime()
 49→          : null;
 50→        const gapSeconds =
 51→          prevMs != null && stepMs != null
 52→            ? Math.max(0, Math.floor((stepMs - prevMs) / 1000))
 53→            : null;
 54→
 55→        const hasNext = index < entries.length - 1;
 56→        const isFirst = index === 0;
 57→        const dotColor =
 58→          entry.step.source === "user"
 59→            ? entry.step.extra?.is_skill_output
 60→              ? "bg-amber-500"
 61→              : "bg-indigo-500"
 62→            : entry.step.source === "system"
 63→              ? "bg-zinc-500"
 64→              : "bg-cyan-500";
 65→
 66→        const actualTime = entry.step.timestamp
 67→          ? formatStepTime(entry.step.timestamp, sessionStartTimestamp)
 68→          : "";
 69→        const fullDateTime = entry.step.timestamp
 70→          ? formatFullDateTime(entry.step.timestamp)
 71→          : "";
 72→
 73→        return (
 74→          <div key={entry.step.step_id} className="flex gap-3">
 75→            {/* Narrow rail: dot + connector */}
 76→            <div className="flex flex-col items-center w-5 shrink-0">
 77→              <div
 78→                className={`w-2 h-2 rounded-full ${dotColor} mt-[7px] shrink-0`}
 79→              />
 80→              {hasNext && (
 81→                <div className="w-px flex-1 bg-zinc-700/40 min-h-[16px]" />
 82→              )}
 83→            </div>
 84→
 85→            {/* Content with inline time header */}
 86→            <div
 87→              className={`flex-1 min-w-0 pb-5 ${!isFirst ? "border-t border-zinc-700/40 pt-3" : ""}`}
 88→            >
 89→              <div
 90→                className="flex items-baseline gap-1.5 mb-1.5 cursor-default"
 91→                title={fullDateTime}
 92→              >
 93→                {elapsedSeconds != null && (
 94→                  <span className="text-xs font-mono text-zinc-400">
 95→                    {formatElapsed(elapsedSeconds)}
 96→                  </span>
 97→                )}
 98→                {actualTime && (
 99→                  <>
100→                    <span className="text-zinc-600 text-[11px]">&middot;</span>
101→                    <span className="text-[11px] font-mono text-zinc-500">
102→                      {actualTime}
103→                    </span>
104→                  </>
105→                )}
106→                {gapSeconds != null && gapSeconds > 0 && (
107→                  <span className="text-[10px] font-mono text-zinc-600 ml-auto">
108→                    +{formatElapsed(gapSeconds)}
109→                  </span>
110→                )}
111→              </div>
112→              {entry.content}
113→            </div>
114→          </div>
115→        );
116→      })}
117→    </>
118→  );
119→}
