121→function findFirstTimestampMs(steps: Step[]): number | null {
122→  for (const step of steps) {
123→    if (step.timestamp) {
124→      const ms = new Date(step.timestamp).getTime();
125→      if (!isNaN(ms)) return ms;
126→    }
127→  }
128→  return null;
129→}
