 1→import { useMemo } from "react";
 2→import { PEAK_HOUR_BINS } from "./chart-constants";
 3→
 4→interface PeakHoursChartProps {
 5→  data: Record<number, number>;
 6→  onHover: (e: React.MouseEvent, text: string) => void;
 7→  onMove: (e: React.MouseEvent) => void;
 8→  onLeave: () => void;
 9→}
10→
11→export function PeakHoursChart({
12→  data,
13→  onHover,
14→  onMove,
15→  onLeave,
16→}: PeakHoursChartProps) {
17→  const bins = useMemo(() => {
18→    return Array.from({ length: PEAK_HOUR_BINS }, (_, i) => {
19→      const h1 = i * 2;
20→      const h2 = h1 + 1;
21→      const c1 = data[h1] ?? data[String(h1) as unknown as number] ?? 0;
22→      const c2 = data[h2] ?? data[String(h2) as unknown as number] ?? 0;
23→      return {
24→        label: `${String(h1).padStart(2, "0")}`,
25→        rangeLabel: `${String(h1).padStart(2, "0")}:00 – ${String(h2).padStart(2, "0")}:59`,
26→        count: c1 + c2,
27→      };
28→    });
29→  }, [data]);
30→  const maxVal = Math.max(1, ...bins.map((b) => b.count));
31→
32→  return (
33→    <div>
34→      <div className="flex items-end gap-1.5 h-24">
35→        {bins.map((bin) => {
36→          const pct = (bin.count / maxVal) * 100;
37→          return (
38→            <div
39→              key={bin.label}
40→              className="flex-1 flex flex-col items-center justify-end h-full cursor-default"
41→              onMouseEnter={(e) =>
42→                onHover(
43→                  e,
44→                  `${bin.rangeLabel}\n${bin.count} session${bin.count !== 1 ? "s" : ""}`
45→                )
46→              }
47→              onMouseMove={onMove}
48→              onMouseLeave={onLeave}
49→            >
50→              <div
51→                className="w-full bg-gradient-to-t from-cyan-600 to-cyan-400 rounded-t transition-all"
52→                style={{
53→                  height: `${Math.max(pct, bin.count > 0 ? 4 : 0)}%`,
54→                }}
55→              />
56→            </div>
57→          );
58→        })}
59→      </div>
60→      <div className="flex gap-1.5 mt-1.5">
61→        {bins.map((bin, i) => (
62→          <div key={bin.label} className="flex-1 text-center text-[10px] text-zinc-400">
63→            {i % 2 === 0 ? bin.label : ""}
64→          </div>
65→        ))}
66→      </div>
67→    </div>
68→  );
69→}
