 1→import { useMemo } from "react";
 2→import { MODEL_COLORS } from "./chart-constants";
 3→import { displayModelName } from "./chart-utils";
 4→
 5→interface ModelDistributionProps {
 6→  data: Record<string, number>;
 7→  onHover: (e: React.MouseEvent, text: string) => void;
 8→  onMove: (e: React.MouseEvent) => void;
 9→  onLeave: () => void;
10→}
11→
12→export function ModelDistribution({
13→  data,
14→  onHover,
15→  onMove,
16→  onLeave,
17→}: ModelDistributionProps) {
18→  const entries = useMemo(
19→    () => Object.entries(data).sort(([, a], [, b]) => b - a),
20→    [data]
21→  );
22→  const total = entries.reduce((s, [, v]) => s + v, 0);
23→
24→  const segments = entries.map(([model, count], i) => ({
25→    model,
26→    count,
27→    pct: total > 0 ? (count / total) * 100 : 0,
28→    color: MODEL_COLORS[i % MODEL_COLORS.length],
29→  }));
30→
31→  return (
32→    <div className="space-y-3">
33→      <div className="h-4 rounded-full overflow-hidden flex bg-zinc-800">
34→        {segments.map((seg) => (
35→          <div
36→            key={seg.model}
37→            className={`h-full ${seg.color} cursor-default`}
38→            style={{ width: `${seg.pct}%` }}
39→            onMouseEnter={(e) =>
40→              onHover(
41→                e,
42→                `${displayModelName(seg.model)}\n${seg.count} session${seg.count !== 1 ? "s" : ""} (${seg.pct.toFixed(1)}%)`
43→              )
44→            }
45→            onMouseMove={onMove}
46→            onMouseLeave={onLeave}
47→          />
48→        ))}
49→      </div>
50→
51→      <div className="space-y-1.5">
52→        {entries.map(([model, count], i) => {
53→          const pct =
54→            total > 0 ? ((count / total) * 100).toFixed(1) : "0";
55→          return (
56→            <div
57→              key={model}
58→              className="flex items-center gap-2.5 text-[13px] cursor-default"
59→              onMouseEnter={(e) =>
60→                onHover(
61→                  e,
62→                  `${displayModelName(model)}\n${count} session${count !== 1 ? "s" : ""} (${pct}%)`
63→                )
64→              }
65→              onMouseMove={onMove}
66→              onMouseLeave={onLeave}
67→            >
68→              <span
69→                className={`w-3 h-3 rounded-sm shrink-0 ${MODEL_COLORS[i % MODEL_COLORS.length]}`}
70→              />
71→              <span
72→                className="flex-1 text-zinc-300 truncate"
73→                title={displayModelName(model)}
74→              >
75→                {displayModelName(model)}
76→              </span>
77→              <span className="text-zinc-400 tabular-nums">
78→                {count} ({pct}%)
79→              </span>
80→            </div>
81→          );
82→        })}
83→        {entries.length === 0 && (
84→          <p className="text-sm text-zinc-500">No data</p>
85→        )}
86→      </div>
87→    </div>
88→  );
89→}
