 26→
 27→function buildPromptEntries(steps: Step[]): PromptEntry[] {
 28→  const entries: PromptEntry[] = [];
 29→  let turnNumber = 0;
 30→
 31→  for (let i = 0; i < steps.length; i++) {
 32→    const step = steps[i];
 33→    if (step.source !== "user") continue;
 34→    if (step.extra?.is_skill_output) continue;
 35→
 36→    const text = extractUserText(step);
 37→    if (!text) continue;
 38→
 39→    turnNumber++;
 40→
 41→    entries.push({
 42→      turnNumber,
 43→      stepId: step.step_id,
 44→      preview: truncate(text.replace(/\n/g, " "), PREVIEW_MAX_CHARS),
 45→    });
 46→  }
 47→
 48→  return entries;
 49→}
